"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import { Button } from "@/components/ui/button";
import {
  Dropzone,
  DropzoneEmptyState,
  DropzoneContent,
} from "@/components/ui/shadcn-io/dropzone";
import { FileText, Image, Sparkles, Download, Loader2 } from "lucide-react";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";

function ThinkingIndicator() {
  const [dots, setDots] = useState("");

  useEffect(() => {
    const interval = setInterval(
      () => setDots((prev) => (prev.length >= 3 ? "" : prev + ".")),
      500
    );
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="flex items-center gap-3 text-slate-500 py-4">
      <div className="flex gap-1">
        <div
          className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"
          style={{ animationDelay: "0ms" }}
        />
        <div
          className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"
          style={{ animationDelay: "150ms" }}
        />
        <div
          className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"
          style={{ animationDelay: "300ms" }}
        />
      </div>
      <span className="text-sm">Processing{dots}</span>
    </div>
  );
}

export default function Home() {
  const [contextFiles, setContextFiles] = useState<File[]>([]);
  const [templateFile, setTemplateFile] = useState<File | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isStreaming, setIsStreaming] = useState(false);

  // Single reasoning block: code interpreter output only
  const [codeOutput, setCodeOutput] = useState("");
  const [codeTokens, setCodeTokens] = useState<string[]>([]);
  const [isCodeStreaming, setIsCodeStreaming] = useState(false);

  // Text output streamed after code is done
  const [textOutput, setTextOutput] = useState("");

  const [downloadPath, setDownloadPath] = useState<string | null>(null);
  const esRef = useRef<EventSource | null>(null);
  const outputEndRef = useRef<HTMLDivElement>(null);

  // Chunk text into fake tokens of 3–4 characters
  const chunkIntoTokens = useCallback((text: string): string[] => {
    const tokens: string[] = [];
    let i = 0;
    while (i < text.length) {
      const chunkSize = Math.floor(Math.random() * 2) + 3; // 3–4 chars
      tokens.push(text.slice(i, i + chunkSize));
      i += chunkSize;
    }
    return tokens;
  }, []);

  // Auto-scroll when output changes
  useEffect(() => {
    outputEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [codeOutput, textOutput]);

  // Fake streaming of code interpreter output into the single reasoning block
  useEffect(() => {
    if (!isCodeStreaming || codeTokens.length === 0) return;

    const nextToken = codeTokens[0];
    const isLast = codeTokens.length === 1;

    const timer = setTimeout(() => {
      setCodeOutput((prev) => prev + nextToken);
      setCodeTokens((prevTokens) => prevTokens.slice(1));
      if (isLast) {
        setIsCodeStreaming(false);
      }
    }, 25);

    return () => clearTimeout(timer);
  }, [isCodeStreaming, codeTokens]);

  const startStream = async () => {
    if (!templateFile) {
      setError("Please upload a template file.");
      return;
    }

    if (esRef.current) {
      esRef.current.close();
      esRef.current = null;
    }

    setError(null);
    setIsStreaming(true);
    setCodeOutput("");
    setCodeTokens([]);
    setIsCodeStreaming(false);
    setTextOutput("");
    setDownloadPath(null);

    try {
      const form = new FormData();
      contextFiles.forEach((f) => form.append("contextFiles", f));
      form.append("templateFiles", templateFile);

      const res = await fetch("/api/upload", { method: "POST", body: form });

      if (!res.ok) {
        setError("Upload failed.");
        setIsStreaming(false);
        return;
      }

      const { jobId } = await res.json();

      const es = new EventSource(`/api/stream/${jobId}`);
      esRef.current = es;

      es.onopen = () => {
        console.log("EventSource connection opened");
      };

      es.onerror = (e) => {
        console.error("EventSource error:", e);
        if (es.readyState === EventSource.CLOSED && !downloadPath) {
          setError("Connection interrupted. The generation may have failed.");
          setIsStreaming(false);
          setIsCodeStreaming(false);
        }
      };

      // CODE INTERPRETER – append all outputs into the single reasoning block
      es.addEventListener(
        "response.code_interpreter_call_code.done",
        (e: MessageEvent) => {
          const raw = e.data ?? "";
          const text = raw.replace(/\\n/g, "\n");
          if (!text.trim()) return;

          const tokens = chunkIntoTokens(text);
          setCodeTokens((prev) => [...prev, ...tokens]);
          setIsCodeStreaming(true);
        }
      );

      // TEXT DELTAS – once these start, we know no more code interpreter output
      es.addEventListener("response.output_text.delta", (e: MessageEvent) => {
        const data = e.data ?? "";
        if (!data) return;

        // Freeze code streaming and only stream text from now on
        setIsCodeStreaming(false);
        setCodeTokens([]);

        setTextOutput((prev) => prev + data);
      });

      // TEXT DONE – optional final chunk
      es.addEventListener("response.output_text.done", (e: MessageEvent) => {
        const finalText = e.data ?? "";
        if (finalText) {
          setTextOutput((prev) => prev + finalText);
        }
      });

      // COMPLETED – expose download link
      es.addEventListener("completed", (e: MessageEvent) => {
        console.log("Completed event received:", e.data);

        setIsCodeStreaming(false);
        setCodeTokens([]);
        setDownloadPath(e.data);
        es.close();
        setIsStreaming(false);
      });

      // ERROR event from server
      es.addEventListener("error", (e: MessageEvent) => {
        console.error("Server error event:", e.data);
        setError(`Server error: ${e.data}`);
        setIsStreaming(false);
        setIsCodeStreaming(false);
        setCodeTokens([]);
        es.close();
      });
    } catch (err) {
      console.error("Stream initialization error:", err);
      setError("Failed to start generation. Please try again.");
      setIsStreaming(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
      {/* Header */}
      <div className="bg-white/80 backdrop-blur-sm border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-6 py-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center">
              <Sparkles className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-2xl font-bold text-slate-900">
              Document Generator
            </h1>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 py-12">
        {/* Instructions Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 mb-8">
          <h2 className="text-lg font-semibold text-slate-900 mb-3">
            How it works
          </h2>
          <div className="flex flex-col md:flex-row gap-6 text-sm text-slate-600">
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                1
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">
                  Add context
                </div>
                Upload images or documents for reference
              </div>
            </div>
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                2
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">
                  Choose template
                </div>
                Upload your document template
              </div>
            </div>
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                3
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">Generate</div>
                Let AI create your document
              </div>
            </div>
          </div>
        </div>

        {/* Upload Section */}
        <div className="grid md:grid-cols-2 gap-6 mb-8">
          {/* Context Files */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4">
              <Image className="w-5 h-5 text-slate-600" />
              <h3 className="text-lg font-semibold text-slate-900">
                Context Files
              </h3>
              <span className="text-xs text-slate-500 ml-auto">Optional</span>
            </div>
            <Dropzone
              maxFiles={100}
              onDrop={setContextFiles}
              src={contextFiles}
              className="border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/50 transition-all rounded-xl bg-slate-50/50"
            >
              <DropzoneEmptyState />
              <DropzoneContent />
            </Dropzone>
            {contextFiles.length > 0 && (
              <p className="text-sm text-slate-600 mt-3">
                {contextFiles.length} file
                {contextFiles.length !== 1 ? "s" : ""} added
              </p>
            )}
          </div>

          {/* Template File */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4">
              <FileText className="w-5 h-5 text-slate-600" />
              <h3 className="text-lg font-semibold text-slate-900">
                Template File
              </h3>
              <span className="text-xs text-red-500 ml-auto">Required</span>
            </div>
            <Dropzone
              maxFiles={1}
              onDrop={(files) => setTemplateFile(files[0] || null)}
              src={templateFile ? [templateFile] : []}
              className="border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/50 transition-all rounded-xl bg-slate-50/50"
            >
              <DropzoneEmptyState />
              <DropzoneContent />
            </Dropzone>
            {templateFile && (
              <p className="text-sm text-slate-600 mt-3">
                {templateFile.name}
              </p>
            )}
          </div>
        </div>

        {/* Error Display */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-xl p-4 mb-6">
            <p className="text-sm text-red-800">{error}</p>
          </div>
        )}

        {/* Generate Button */}
        <div className="flex justify-center mb-8">
          <Button
            onClick={startStream}
            disabled={!templateFile || isStreaming}
            size="lg"
            className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white px-8 py-6 text-lg rounded-xl shadow-lg hover:shadow-xl transition-all disabled:opacity-50"
          >
            {isStreaming ? (
              <>
                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                Generating...
              </>
            ) : (
              <>
                <Sparkles className="w-5 h-5 mr-2" />
                Generate Document
              </>
            )}
          </Button>
        </div>

        {/* Output Section */}
        {(isStreaming ||
          codeOutput ||
          textOutput ||
          downloadPath) && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
              <Sparkles className="w-5 h-5 text-blue-600" />
              Generation Progress
            </h3>

            <div className="space-y-4">
              {/* Single reasoning block for code interpreter output */}
              {(codeOutput || isCodeStreaming) && (
                <Reasoning
                  className="w-full"
                  isStreaming={isCodeStreaming}
                >
                  <ReasoningTrigger />
                  <ReasoningContent>{codeOutput}</ReasoningContent>
                </Reasoning>
              )}

              {/* Text output streamed after code is done */}
              {textOutput && (
                <div className="rounded-lg border border-slate-200 bg-slate-50 p-4 text-sm whitespace-pre-wrap">
                  {textOutput}
                </div>
              )}

              {/* Thinking indicator if streaming but nothing yet */}
              {isStreaming && !codeOutput && !textOutput && (
                <ThinkingIndicator />
              )}

              {/* Download Button below the text output */}
              {downloadPath && (
                <div className="pt-4 border-t border-slate-200">
                  <a
                    href={downloadPath}
                    download
                    className="inline-flex items-center gap-2 bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 text-white px-6 py-3 rounded-lg shadow-md hover:shadow-lg transition-all"
                  >
                    <Download className="w-5 h-5" />
                    Download Completed Document
                  </a>
                </div>
              )}

              <div ref={outputEndRef} />
            </div>
          </div>
        )}
      </div>
    </div>
  );
}